"use client"

import * as React from "react"
import type { ColumnDef } from "@tanstack/react-table"

import {
  AnalyticsCard,
  Badge,
  BarChart,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  DataTable,
  Delta,
  DistributionBar,
  LabeledDonutCard,
  LineChart,
  Meter,
  PersonCell,
  Separator,
  StatGroup,
  ToggleGroup,
  ToggleGroupItem,
  formatCurrency,
  formatNumber,
  formatPercent,
} from "@gunjo/ui"

import {
  CHANNELS,
  type Channel,
  type DriverRow,
  DRIVERS,
  KPI_BY_PERIOD,
  type Period,
  PERIOD_LABEL,
  REVENUE_TREND,
  TIME_BANDS,
} from "./data"

const yen = (n: number) => formatCurrency(n)
const yenCompact = (n: number) => formatCurrency(n, { compact: true, maximumFractionDigits: 1 })
const signedYen = (n: number) => formatCurrency(n, { signed: true })

/** チャネル別の固定トーン（順序が変わっても色がブレないように明示）。 */
const CHANNEL_TONE: Record<string, "primary" | "info" | "accent" | "muted"> = {
  配車アプリ: "primary",
  無線: "info",
  流し: "accent",
  "乗り場・専属": "muted",
}

const driverColumns: ColumnDef<DriverRow>[] = [
  {
    accessorKey: "rank",
    header: "順位",
    cell: ({ row }) => {
      const r = row.original.rank
      const medal = r <= 3
      return (
        <span
          className={
            "inline-flex h-7 w-7 items-center justify-center rounded-full text-sm font-bold tabular-nums " +
            (medal ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground")
          }
          aria-label={`第${r}位`}
        >
          {r}
        </span>
      )
    },
    enableSorting: false,
  },
  {
    accessorKey: "name",
    header: "乗務員",
    cell: ({ row }) => {
      const d = row.original
      return (
        <PersonCell
          size="sm"
          name={d.name}
          secondary={`${d.id} ・ ${d.shift}`}
          trailing={d.excellent ? <Badge variant="success">優良</Badge> : undefined}
        />
      )
    },
  },
  {
    accessorKey: "revenue",
    header: "水揚",
    cell: ({ row }) => (
      <span className="font-semibold tabular-nums">{yen(row.original.revenue)}</span>
    ),
  },
  {
    accessorKey: "trips",
    header: "営業回数",
    cell: ({ row }) => <span className="tabular-nums">{row.original.trips}回</span>,
  },
  {
    accessorKey: "jissyaRate",
    header: "実車率",
    cell: ({ row }) => (
      <span className="tabular-nums">{formatPercent(row.original.jissyaRate)}</span>
    ),
  },
  {
    accessorKey: "dod",
    header: "前日比",
    cell: ({ row }) => (
      <Delta
        value={row.original.dod}
        format={signedYen}
        labels={{ positive: "増", negative: "減", zero: "増減なし" }}
      />
    ),
  },
]

export function RevenueDashboard() {
  const [period, setPeriod] = React.useState<Period>("today")

  const kpi = KPI_BY_PERIOD[period]
  const trend = REVENUE_TREND[period]
  const bands = TIME_BANDS[period]
  const channels: Channel[] = CHANNELS[period]

  const channelTotal = channels.reduce((s, c) => s + c.revenue, 0)
  const budgetPct = Math.round((kpi.totalRevenue / kpi.budget) * 100)

  const trendData = trend.points.map((p) => ({
    label: p.label,
    value: p.value,
  }))

  // 時間帯別：縦棒。ピーク帯は primary、それ以外は muted で突出を強調。
  const bandData = bands.map((b) => ({
    label: b.band,
    value: b.revenue,
    color: (b.peak ? "primary" : "muted") as "primary" | "muted",
  }))

  const channelSegments = channels.map((c) => ({
    label: c.name,
    value: c.revenue,
    color: CHANNEL_TONE[c.name] ?? "muted",
  }))

  return (
    <div className="space-y-6">
      {/* ── 期間フィルタ ─────────────────────────────────────────────── */}
      <div className="flex flex-wrap items-center justify-between gap-3">
        <ToggleGroup
          type="single"
          value={period}
          onValueChange={(v) => {
            if (v) setPeriod(v as Period)
          }}
          disallowEmpty
          variant="outline"
          aria-label="集計期間"
        >
          {(Object.keys(PERIOD_LABEL) as Period[]).map((p) => (
            <ToggleGroupItem key={p} value={p}>
              {PERIOD_LABEL[p]}
            </ToggleGroupItem>
          ))}
        </ToggleGroup>
        <p className="text-xs text-muted-foreground" aria-live="polite">
          表示中: <span className="font-medium text-foreground">{PERIOD_LABEL[period]}</span> の実績
        </p>
      </div>

      {/* ── KPI サマリ（4枚のヒーローカード・差分付き） ─────────────────── */}
      <section aria-label="主要指標">
        <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 xl:grid-cols-4">
          <AnalyticsCard
            title="日車営収"
            titleAs="h3"
            description="1台1日あたり売上"
            value={yen(kpi.nissyaEisyu)}
            trend={kpi.nissyaEisyuYoy >= 0 ? "up" : "down"}
            delta={
              <Delta
                value={kpi.nissyaEisyuYoy}
                format={signedYen}
                labels={{ positive: "増加", negative: "減少", zero: "横ばい" }}
              />
            }
            deltaDescription="前年同月比"
          />
          <AnalyticsCard
            title="総水揚"
            titleAs="h3"
            description={`稼働 ${kpi.activeVehicles}台 / 全${78}台`}
            value={yenCompact(kpi.totalRevenue)}
            trend={kpi.totalRevenueDelta >= 0 ? "up" : "down"}
            delta={
              <Delta
                value={kpi.totalRevenueDelta}
                format={(n) => formatCurrency(n, { signed: true, compact: true, maximumFractionDigits: 1 })}
                labels={{ positive: "増加", negative: "減少", zero: "横ばい" }}
              />
            }
            deltaDescription="前期比"
          />
          <AnalyticsCard
            title="実車率"
            titleAs="h3"
            description="実車キロ ÷ 走行キロ"
            value={formatPercent(kpi.jissyaRate)}
            trend={kpi.jissyaRateDelta >= 0 ? "up" : "down"}
            delta={
              <Delta
                value={Math.round(kpi.jissyaRateDelta * 1000) / 10}
                format={(n) => `${n > 0 ? "+" : ""}${n.toFixed(1)}pt`}
                labels={{ positive: "改善", negative: "悪化", zero: "横ばい" }}
              />
            }
            deltaDescription="前期比"
          />
          <AnalyticsCard
            title="稼働率"
            titleAs="h3"
            description="実働 ÷ 在籍車両"
            value={formatPercent(kpi.utilization)}
            trend={kpi.utilizationDelta >= 0 ? "up" : "down"}
            variant={kpi.utilizationDelta < 0 ? "riskIncrease" : "default"}
            delta={
              <Delta
                value={Math.round(kpi.utilizationDelta * 1000) / 10}
                format={(n) => `${n > 0 ? "+" : ""}${n.toFixed(1)}pt`}
                labels={{ positive: "改善", negative: "悪化", zero: "横ばい" }}
              />
            }
            deltaDescription="前期比"
          />
        </div>
      </section>

      {/* ── 営収の推移 + 目標達成 ───────────────────────────────────── */}
      <section className="grid grid-cols-1 gap-4 lg:grid-cols-3" aria-label="営収の推移と目標達成">
        <Card className="lg:col-span-2">
          <CardHeader className="flex-row items-start justify-between gap-2 space-y-0">
            <div>
              <CardTitle className="text-base">営収の推移（{trend.unit}）</CardTitle>
              <CardDescription>
                直近{trend.points.length}{period === "month" ? "か月" : "日"}・破線は目標 {yen(trend.target)}
              </CardDescription>
            </div>
            <Badge variant="outline">{PERIOD_LABEL[period]}</Badge>
          </CardHeader>
          <CardContent>
            <LineChart
              variant="area"
              series={[{ label: trend.unit, data: trendData, color: "primary" }]}
              referenceValue={trend.target}
              referenceLabel="目標"
              showGrid
              showDots
              showLabels
              formatValue={(n) => formatCurrency(n, { compact: true, maximumFractionDigits: 1 })}
            />
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="text-base">月間予算 達成率</CardTitle>
            <CardDescription>総水揚 vs 予算</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex items-end justify-between gap-2">
              <div>
                <p className="text-3xl font-bold tabular-nums">{budgetPct}%</p>
                <p className="text-xs text-muted-foreground">
                  {yenCompact(kpi.totalRevenue)} / {yenCompact(kpi.budget)}
                </p>
              </div>
              <Delta
                value={kpi.totalRevenue - kpi.budget}
                format={(n) => formatCurrency(n, { signed: true, compact: true, maximumFractionDigits: 1 })}
                labels={{ positive: "予算超過", negative: "予算未達", zero: "予算どおり" }}
                showLabel
                className="text-xs"
              />
            </div>
            <Meter
              value={kpi.totalRevenue}
              max={kpi.budget}
              direction="fill-is-good"
              label="月間予算達成"
              valueText={`${yen(kpi.totalRevenue)} / 予算 ${yen(kpi.budget)}（${budgetPct}%）`}
              formatValue={(n) => formatCurrency(n, { compact: true, maximumFractionDigits: 1 })}
            />
            <Separator />
            <dl className="grid grid-cols-2 gap-3 text-sm">
              <div>
                <dt className="text-xs text-muted-foreground">営業回数</dt>
                <dd className="font-semibold tabular-nums">{formatNumber(kpi.trips)}回</dd>
              </div>
              <div>
                <dt className="text-xs text-muted-foreground">客単価</dt>
                <dd className="font-semibold tabular-nums">{yen(kpi.farePerTrip)}</dd>
              </div>
            </dl>
          </CardContent>
        </Card>
      </section>

      {/* ── 時間帯別 + チャネル構成比 ───────────────────────────────── */}
      <section className="grid grid-cols-1 gap-4 lg:grid-cols-2" aria-label="時間帯別の需要とチャネル構成比">
        <Card>
          <CardHeader>
            <CardTitle className="text-base">時間帯別の営収</CardTitle>
            <CardDescription>濃い棒がピーク帯（日中・夜間）。深夜は割増運賃</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <BarChart
              variant="vertical"
              data={bandData}
              showLabels
              showValues
              formatValue={(n) => formatCurrency(n, { compact: true, maximumFractionDigits: 1 })}
            />
            <div className="grid grid-cols-2 gap-2 text-xs sm:grid-cols-4">
              {bands.map((b) => (
                <div key={b.band} className="rounded-md border border-border bg-muted/30 px-2 py-1.5">
                  <p className="font-medium">{b.band}</p>
                  <p className="text-muted-foreground">{b.hours}時</p>
                  <p className="tabular-nums">{formatNumber(b.trips)}回</p>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>

        <LabeledDonutCard
          title="獲得チャネル構成比"
          description="総水揚に占める割合"
          segments={channelSegments}
          centerLabel="総水揚"
          centerValue={yenCompact(channelTotal)}
          showCallouts
          formatValue={yen}
          totalLabel="総水揚"
        />
      </section>

      {/* ── チャネル別 内訳バー（1本・割合の即読み） ───────────────────── */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base">チャネル別 内訳</CardTitle>
          <CardDescription>1本バーで構成比を即読み。配車アプリ比率が収益の鍵</CardDescription>
        </CardHeader>
        <CardContent>
          <DistributionBar segments={channelSegments} showLegend formatValue={yen} totalLabel="総水揚" />
        </CardContent>
      </Card>

      {/* ── 乗務員別ランキング（水揚順） ─────────────────────────────── */}
      <Card>
        <CardHeader className="flex-row items-center justify-between gap-2 space-y-0">
          <div>
            <CardTitle className="text-base">乗務員別ランキング（水揚順）</CardTitle>
            <CardDescription>本日確定。列ヘッダで並べ替え可能</CardDescription>
          </div>
          <Badge variant="secondary">{DRIVERS.length}名表示</Badge>
        </CardHeader>
        <CardContent>
          <DataTable<DriverRow, unknown>
            columns={driverColumns}
            data={DRIVERS}
            pageSize={12}
            filter={null}
          />
        </CardContent>
      </Card>
    </div>
  )
}
